        private const int GirlDisplayWidth = 74;

        private static readonly string[] LogoLines = new[]
        {
            @"████████╗███████╗███╗   ██╗███████╗ ██████╗ ██████╗ ███████╗██╗  ██╗ █████╗ ██████╗ ██████╗ ",
            @"╚══██╔══╝██╔════╝████╗  ██║██╔════╝██╔═══██╗██╔══██╗██╔════╝██║  ██║██╔══██╗██╔══██╗██╔══██╗",
            @"   ██║   █████╗  ██╔██╗ ██║███████╗██║   ██║██████╔╝███████╗███████║███████║██████╔╝██████╔╝",
            @"   ██║   ██╔══╝  ██║╚██╗██║╚════██║██║   ██║██╔══██╗╚════██║██╔══██║██╔══██║██╔══██╗██╔═══╝ ",
            @"   ██║   ███████╗██║ ╚████║███████║╚██████╔╝██║  ██║███████║██║  ██║██║  ██║██║  ██║██║     ",
            @"   ╚═╝   ╚══════╝╚═╝  ╚═══╝╚══════╝ ╚═════╝ ╚═╝  ╚═╝╚══════╝╚═╝  ╚═╝╚═╝  ╚═╝╚═╝  ╚═╝╚═╝",
        };

        private const string Tagline = "Open-Source Deep Learning / AI C# Library";
        private const string Url = "https://github.com/zhongkaifu/TensorSharp";

        private static readonly (int R, int G, int B)[] Gradient =
        {
            (59, 130, 246),
            (6, 182, 212),
            (20, 184, 166),
            (245, 158, 11),
            (217, 70, 239),
            (99, 102, 241),
        };

        private static readonly (string Symbol, int R, int G, int B)[] Cubes =
        {
            ("\u25C6",  59, 130, 246),
            ("\u25C7",   6, 182, 212),
            ("\u25C8", 245, 158, 11),
            ("\u25C7", 217,  70, 239),
            ("\u25C6",  99, 102, 241),
            ("\u25C8",  20, 184, 166),
            ("\u25C7", 245, 158,  11),
            ("\u25C6", 217,  70, 239),
            ("\u25C7",  59, 130, 246),
        };

        public static void Print()
        {
            bool color = !Console.IsOutputRedirected
                         && Environment.GetEnvironmentVariable("NO_COLOR") == null;

            int logoWidth = 0;
            foreach (var line in LogoLines)
                if (line.Length > logoWidth) logoWidth = line.Length;

            var sb = new StringBuilder(65536);
            sb.AppendLine();

            if (color)
                BuildColor(sb, logoWidth);
            else
                BuildPlain(sb, logoWidth);

            sb.AppendLine();
            Console.Write(sb.ToString());
        }

        private static void BuildColor(StringBuilder sb, int logoWidth)
        {
            const string Reset = "\x1b[0m";

            // Girl art on top, centered relative to the logo width
            int girlPad = Math.Max(0, (logoWidth - GirlDisplayWidth) / 2);
            string girlIndent = girlPad > 0 ? new string(' ', girlPad) : "";

            foreach (var line in GirlArt)
            {
                sb.Append(girlIndent);
                sb.AppendLine(line);
            }

            sb.AppendLine();

            // Cube decoration
            int cubeSpacing = logoWidth / (Cubes.Length + 1);
            sb.Append("  ");
            int cursor = 0;
            for (int i = 0; i < Cubes.Length; i++)
            {
                int target = cubeSpacing * (i + 1);
                if (target > cursor) { sb.Append(new string(' ', target - cursor)); cursor = target; }
                var c = Cubes[i];
                sb.Append($"\x1b[38;2;{c.R};{c.G};{c.B}m{c.Symbol}{Reset}");
                cursor++;
            }
            sb.AppendLine();

            // Logo text with gradient
            for (int row = 0; row < LogoLines.Length; row++)
            {
                string line = LogoLines[row];
                float brightness = 1.0f - row * 0.04f;
                sb.Append("  ");
                for (int col = 0; col < line.Length; col++)
                {
                    char ch = line[col];
                    if (ch == ' ') { sb.Append(' '); continue; }
                    float t = (float)col / Math.Max(1, line.Length - 1);
                    var (r, g, b) = Lerp(t);
                    r = Clamp((int)(r * brightness));
                    g = Clamp((int)(g * brightness));
                    b = Clamp((int)(b * brightness));
                    sb.Append($"\x1b[38;2;{r};{g};{b}m{ch}");
                }
                sb.Append(Reset);
                sb.AppendLine();
            }

            sb.AppendLine();
            CenterColored(sb, Tagline, logoWidth, 6, 182, 212);
            CenterColored(sb, Url, logoWidth, 100, 116, 139);
        }

        private static void BuildPlain(StringBuilder sb, int logoWidth)
        {
            foreach (var line in LogoLines)
            {
                sb.Append("  ");
                sb.AppendLine(line);
            }
            sb.AppendLine();
            CenterPlain(sb, Tagline, logoWidth);
            CenterPlain(sb, Url, logoWidth);
        }

        private static void CenterColored(StringBuilder sb, string text, int width,
            int r, int g, int b)
        {
            int pad = Math.Max(0, (width - text.Length) / 2 + 2);
            sb.Append(new string(' ', pad));
            sb.Append($"\x1b[38;2;{r};{g};{b}m{text}\x1b[0m");
            sb.AppendLine();
        }

        private static void CenterPlain(StringBuilder sb, string text, int width)
        {
            int pad = Math.Max(0, (width - text.Length) / 2 + 2);
            sb.Append(new string(' ', pad));
            sb.AppendLine(text);
        }

        private static (int R, int G, int B) Lerp(float t)
        {
            t = Math.Max(0f, Math.Min(1f, t));
            float seg = t * (Gradient.Length - 1);
            int i = Math.Min((int)seg, Gradient.Length - 2);
            float frac = seg - i;
            var a = Gradient[i];
            var b = Gradient[i + 1];
            return (
                (int)(a.R + (b.R - a.R) * frac),
                (int)(a.G + (b.G - a.G) * frac),
                (int)(a.B + (b.B - a.B) * frac));
        }

        private static int Clamp(int v) => v < 0 ? 0 : v > 255 ? 255 : v;
    }
